3	// LAYER 1 of the GraphQL multi-project leak fix (ddx-4c51d33e).
4	// Verifies the scoped /api/projects/{project}/graphql endpoint isolates
5	// resolver WorkingDir per request, and that the legacy /graphql route
6	// continues to serve the server's startup project.
7	
8	import (
9		"bytes"
10		"encoding/json"
