19	// seedDocsProject creates a temp project rooted at root with a single
20	// docgraph-tracked markdown document carrying the given DDx id and title.
21	// Returns the absolute project path and the document's relative path.
22	func seedDocsProject(t *testing.T, root, name, docID, title string) (string, string) {
23		t.Helper()
24		projectPath := filepath.Join(root, name)
25		if err := os.MkdirAll(filepath.Join(projectPath, ".ddx"), 0o755); err != nil {
26			t.Fatal(err)
27		}
28		cfg := `version: "1.0"
29	library:
30	  path: ".ddx/plugins/ddx"
31	  repository:
32	    url: "https://example.com/lib"
33	    branch: "main"
34	`
35		if err := os.WriteFile(filepath.Join(projectPath, ".ddx", "config.yaml"), []byte(cfg), 0o644); err != nil {
36			t.Fatal(err)
37		}
38		docsDir := filepath.Join(projectPath, "docs")
39		if err := os.MkdirAll(docsDir, 0o755); err != nil {
40			t.Fatal(err)
41		}
42		relPath := filepath.Join("docs", docID+".md")
43		body := "---\nddx:\n  id: " + docID + "\n---\n# " + title + "\n\nbody for " + docID + "\n"
44		if err := os.WriteFile(filepath.Join(projectPath, relPath), []byte(body), 0o644); err != nil {
45			t.Fatal(err)
46		}
47		return projectPath, relPath
48	}
