50	// postGraphQL fires a POST against the given path on srv and returns the
51	// response recorder. Sets RemoteAddr so isTrusted() accepts the request.
52	func postGraphQL(t *testing.T, srv *Server, path, query string) *httptest.ResponseRecorder {
53		t.Helper()
54		body, _ := json.Marshal(map[string]string{"query": query})
55		req := httptest.NewRequest(http.MethodPost, path, bytes.NewReader(body))
56		req.Header.Set("Content-Type", "application/json")
57		req.RemoteAddr = "127.0.0.1:12345"
58		w := httptest.NewRecorder()
59		srv.Handler().ServeHTTP(w, req)
60		return w
61	}
