63	// TestGraphQL_ScopedRoute_DocumentByPath_OnlyReturnsScopedProjectDocs is
64	// AC #5 of ddx-4c51d33e: a query against project B's scoped GraphQL endpoint
65	// must read project B's documents, not the server's startup project (A).
66	func TestGraphQL_ScopedRoute_DocumentByPath_OnlyReturnsScopedProjectDocs(t *testing.T) {
67		t.Setenv("XDG_DATA_HOME", t.TempDir())
68		t.Setenv("DDX_NODE_NAME", "gql-scope-test")
69	
70		root := t.TempDir()
71		projA, relA := seedDocsProject(t, root, "proj-a", "alpha", "Alpha A")
72		projB, relB := seedDocsProject(t, root, "proj-b", "beta", "Beta B")
73	
74		srv := New(":0", projA)
75		t.Cleanup(func() { _ = srv.Shutdown() })
76		entryB := srv.state.RegisterProject(projB)
77	
78		// 1. Hit the scoped endpoint for project B asking for B's document by path.
79		queryB := `{ documentByPath(path: "` + filepath.ToSlash(relB) + `") { id path content } }`
80		w := postGraphQL(t, srv, "/api/projects/"+entryB.ID+"/graphql", queryB)
81		if w.Code != http.StatusOK {
82			t.Fatalf("scoped B query: status=%d body=%s", w.Code, w.Body.String())
83		}
84		var resp struct {
85			Data struct {
86				DocumentByPath *struct {
87					ID      string  `json:"id"`
88					Path    string  `json:"path"`
89					Content *string `json:"content"`
90				} `json:"documentByPath"`
91			} `json:"data"`
92			Errors []map[string]any `json:"errors"`
93		}
94		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
95			t.Fatalf("decode resp: %v body=%s", err, w.Body.String())
96		}
97		if len(resp.Errors) != 0 {
98			t.Fatalf("scoped B query errors: %v", resp.Errors)
99		}
100		if resp.Data.DocumentByPath == nil {
101			t.Fatalf("scoped B query: documentByPath is null, expected B's document")
102		}
103		if resp.Data.DocumentByPath.Content == nil || !strings.Contains(*resp.Data.DocumentByPath.Content, "Beta B") {
104			t.Fatalf("scoped B query: expected B's content, got %+v", resp.Data.DocumentByPath)
105		}
106	
107		// 2. Asking the scoped B endpoint for A's document path must NOT find it
108		//    (resolves to null since A's doc does not exist under B's project root).
109		queryAOnB := `{ documentByPath(path: "` + filepath.ToSlash(relA) + `") { id path content } }`
110		w2 := postGraphQL(t, srv, "/api/projects/"+entryB.ID+"/graphql", queryAOnB)
111		if w2.Code != http.StatusOK {
112			t.Fatalf("cross-project leak query: status=%d body=%s", w2.Code, w2.Body.String())
113		}
114		var resp2 struct {
115			Data struct {
116				DocumentByPath *struct {
117					ID      string  `json:"id"`
118					Content *string `json:"content"`
119				} `json:"documentByPath"`
120			} `json:"data"`
121		}
122		_ = json.Unmarshal(w2.Body.Bytes(), &resp2)
123		if resp2.Data.DocumentByPath != nil {
124			// If non-null and content contains A's title, that's the leak we're
125			// guarding against. The naming `relA` happens to equal `relB` so this
126			// also implicitly proves we're not reading from project A's filesystem.
127			if resp2.Data.DocumentByPath.Content != nil && strings.Contains(*resp2.Data.DocumentByPath.Content, "Alpha A") {
128				t.Fatalf("CROSS-PROJECT LEAK: scoped B endpoint returned A's content: %+v", resp2.Data.DocumentByPath)
129			}
130		}
131	}
