133	// TestGraphQL_ScopedRoute_RejectsUnregisteredProject is AC #6: the scoped
134	// route must 404 when the path's project segment doesn't resolve.
135	func TestGraphQL_ScopedRoute_RejectsUnregisteredProject(t *testing.T) {
136		t.Setenv("XDG_DATA_HOME", t.TempDir())
137		t.Setenv("DDX_NODE_NAME", "gql-scope-404-test")
138	
139		root := t.TempDir()
140		projA, _ := seedDocsProject(t, root, "proj-a", "alpha", "Alpha A")
141	
142		srv := New(":0", projA)
143		t.Cleanup(func() { _ = srv.Shutdown() })
144	
145		w := postGraphQL(t, srv, "/api/projects/unknown-project-id/graphql", `{ __typename }`)
146		if w.Code != http.StatusNotFound {
147			t.Fatalf("unregistered project: want 404, got %d body=%s", w.Code, w.Body.String())
148		}
149	}
