151	// TestGraphQL_LegacyRoute_StillWorks is AC #4 + #7: the unchanged /graphql
152	// trusted route continues to serve the server's startup project.
153	func TestGraphQL_LegacyRoute_StillWorks(t *testing.T) {
154		t.Setenv("XDG_DATA_HOME", t.TempDir())
155		t.Setenv("DDX_NODE_NAME", "gql-legacy-test")
156	
157		root := t.TempDir()
158		projA, relA := seedDocsProject(t, root, "proj-a", "alpha", "Alpha A")
159		projB, _ := seedDocsProject(t, root, "proj-b", "beta", "Beta B")
160	
161		srv := New(":0", projA)
162		t.Cleanup(func() { _ = srv.Shutdown() })
163		srv.state.RegisterProject(projB)
164	
165		query := `{ documentByPath(path: "` + filepath.ToSlash(relA) + `") { id content } }`
166		w := postGraphQL(t, srv, "/graphql", query)
167		if w.Code != http.StatusOK {
168			t.Fatalf("legacy query: status=%d body=%s", w.Code, w.Body.String())
169		}
170		var resp struct {
171			Data struct {
172				DocumentByPath *struct {
173					ID      string  `json:"id"`
174					Content *string `json:"content"`
175				} `json:"documentByPath"`
176			} `json:"data"`
177			Errors []map[string]any `json:"errors"`
178		}
179		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
180			t.Fatalf("decode legacy resp: %v body=%s", err, w.Body.String())
181		}
182		if len(resp.Errors) != 0 {
183			t.Fatalf("legacy query errors: %v", resp.Errors)
184		}
185		if resp.Data.DocumentByPath == nil {
186			t.Fatalf("legacy query: expected A's document, got null")
187		}
188		if resp.Data.DocumentByPath.Content == nil || !strings.Contains(*resp.Data.DocumentByPath.Content, "Alpha A") {
189			t.Fatalf("legacy query: expected A's content, got %+v", resp.Data.DocumentByPath)
190		}
191	}
